// Deduplicate by symbol — first occurrence wins
const _seen = new Set<string>();
const _deduped: StockInfo[] = [];
for (const s of STOCKS_LIST) {
  if (!_seen.has(s.symbol.toUpperCase())) {
    _seen.add(s.symbol.toUpperCase());
    _deduped.push(s);
  }
}
// Replace array contents in-place so the exported reference stays valid
STOCKS_LIST.length = 0;
for (const s of _deduped) STOCKS_LIST.push(s);

// Build a map for O(1) lookup by symbol
export const STOCKS_MAP = new Map<string, StockInfo>(
  STOCKS_LIST.map(s => [s.symbol.toUpperCase(), s])
);
